CREATE OR REPLACE FUNCTION fpb_fin_get_money_return_date ( as_memno sc_fin_money_return.membership_no%type , ai_seq sc_fin_money_return.item_no%type , adtm_return timestamp(0) DEFAULT null) RETURNS timestamp(0) AS $body$
DECLARE

ldtm_jourdate sc_fin_vourcher_head.journal_date%type;
ls_return_status sc_fin_money_return.return_status%type;
ls_paid_method   sc_fin_money_return.paid_method%type;
li_rkeep_year   sc_fin_money_return.rkeep_year%type;
li_rkeep_month  sc_fin_money_return.rkeep_month%type;
ldt_paiddate timestamp(0);

BEGIN
  begin
    select	return_status ,paid_method
    ,rkeep_year , rkeep_month ,paid_date
    into STRICT ls_return_status , ls_paid_method
    ,li_rkeep_year , li_rkeep_month ,ldt_paiddate
    from 		sc_fin_money_return
    where 	membership_no = as_memno
    and 		item_no = ai_seq;
  exception when no_data_found then CALL spa_dberror('E18:ไม่มีรายการรอจ่าย');
  end;
  case ls_return_status
  when '0' then
    --ยังไม่คืน
    RETURN null;
  when '1' then
      if trim(both ls_paid_method ) = 'KEP'then
          select receipt_date into STRICT ldtm_jourdate
          from sc_kep_m_monthly_process
          where  receive_year = li_rkeep_year
          and receive_month = li_rkeep_month
;
      elsif coalesce(ldt_paiddate::text, '') = '' then
         --ไม่ได้ระบุวันจ่ายคืน หาจาก vourcher แต่ไม่น่าเข้าเคสนี้เลย 
         --ตัดจ่ายจากหน้าจอ จ่ายรอจ่ายคืน
          begin

            select sc_fin_vourcher_head.journal_date
            into STRICT ldtm_jourdate
            from sc_fin_vourcher_head
            ,sc_fin_money_return_det
            where sc_fin_vourcher_head.cancel_status ='0'     
            and sc_fin_vourcher_head.post_journal = '1'
            and sc_fin_vourcher_head.vourcher_no = sc_fin_money_return_det.voucher_no 
            and sc_fin_money_return_det.item_type != 'EN'
            and sc_fin_money_return_det.status = '0'
            and sc_fin_money_return_det.membership_no = as_memno
            and sc_fin_money_return_det.item_no = ai_seq
;
            exception 
            when no_data_found then  return null;
            when others then CALL spa_dberror('FPB_FIN_GET_MONEY_RETURN_DATE');
          end;
        else
         --ระบุวันจ่ายคืนมา ก้อไม่ต้องหาแล้ว
         return ldt_paiddate;
      end if;
  when '2' then

    --จ่ายจากการทำไฟล์โอนเข้าเงินฝาก SCTELRTI >> PKA_DEP_TRANS
       begin
         select max(sc_fin_vourcher_head.journal_date) into STRICT ldtm_jourdate
        from sc_fin_vourcher_head
        ,sc_fin_money_return_det
        where sc_fin_vourcher_head.cancel_status ='0'
        and sc_fin_vourcher_head.post_journal = '1'
        and sc_fin_vourcher_head.ref_docno = sc_fin_money_return_det.dep_group_no
        and sc_fin_money_return_det.item_type != 'EN'
        and sc_fin_money_return_det.status = '0'
        and sc_fin_money_return_det.membership_no = as_memno
        and sc_fin_money_return_det.item_no = ai_seq
;


        exception
        when no_data_found then  return null;
        when others then CALL spa_dberror('FPB_FIN_GET_MONEY_RETURN_DATE');
      end;
  else
    CALL spa_dberror('Not in Case');
  end case;

--หา ณ วันที่ 30/9/2020  
--  if ldtm_jourdate > adtm_return and adtm_return is not null then 
--    RETURN null ; 
--  end if ;
  RETURN ldtm_jourdate;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
